item.command:
$moves = @(
  @{ From = "C:\Users\mrbla\BlarAI\sprints";              To = "C:\Users\mrbla\BlarAI\.platform\sprints" },
  @{ From = "C:\Users\mrbla\BlarAI\scheduled";            To = "C:\Users\mrbla\BlarAI\.platform\scheduled" },
  @{ From = "C:\Users\mrbla\BlarAI\docs\active_tasks.yaml"; To = "C:\Users\mrbla\BlarAI\.platform\active_tasks.yaml" },
  @{ From = "C:\Users\mrbla\BlarAI\docs\sprints";          To = "C:\Users\mrbla\BlarAI\.platform\docs_sprints" }
)
foreach ($m in $moves) {
  if (-not (Test-Path $m.From)) { Write-Host "SKIP (missing): $($m.From)"; continue }
  if (Test-Path $m.To) { throw "Destination already exists: $($m.To). Refusing to overwrite." }
  $parent = Split-Path $m.To -Parent
  if (-not (Test-Path $parent)) { New-Item -ItemType Directory -Path $parent -Force | Out-Null }
  Move-Item -Path $m.From -Destination $m.To
  Write-Host "MOVED: $($m.From) -> $($m.To)"
}

# Trigger a scheduled task and verify it reads BlarAI/.platform/sprints/ correctly
Start-ScheduledTask -TaskName "BlarAI_daily_digest";
Start-Sleep 20;
Get-ScheduledTask -TaskName "BlarAI_daily_digest" | Get-ScheduledTaskInfo | Select LastTaskResult

cd C:\Users\mrbla\BlarAI;
git add -A;
git commit -m "Extract platform layer to devplatform (Stages 2-5)";
# --- HALT: present diff summary + test baseline to Lead Architect, then STOP ---
git log --oneline main..HEAD;
git diff main --stat;
Write-Host '';
Write-Host '*** STOP: Lead Architect approval required before merging to main. ***' -ForegroundColor Yellow;
Write-Host 'After approval, run the merge block below:' -ForegroundColor Yellow;
Write-Host '  cd C:\Users\mrbla\BlarAI;' -ForegroundColor Yellow;
Write-Host '  git checkout main;' -ForegroundColor Yellow;
Write-Host '  git merge --no-ff chore/platform-extraction -m "Merge platform extraction to main";' -ForegroundColor Yellow;
Write-Host '  # Do NOT delete chore/platform-extraction branch — keep for audit per copilot-instructions preservation rule.' -ForegroundColor Yellow;
